// src/recon/cursor.ts
// Pages through the ledger in batches for the nightly reconciliation job. Unlike the
// stateless transform stages above, this stage carries pagination state across batches.
// BUG: nextBatch() advances the page cursor to the next page as soon as it reads the
// current page — BEFORE that batch has been acknowledged by the downstream writer. If a
// batch fails mid-flight and is retried, the cursor has already moved past those rows, so
// the unacknowledged transactions are never re-read and are dropped from reconciliation.
export async function nextBatch(state: CursorState): Promise<Batch> {
  const batch = await readPage(state.cursor, state.pageSize);
  state.cursor = batch.nextCursor; // advances before the batch is acknowledged
  return batch;
}

export function ack(state: CursorState, batch: Batch): void {
  // The cursor should only advance here, after a durable ack — but it was already moved
  // in nextBatch(), so this just records the ack and the skipped rows are lost.
  state.lastAcked = batch.id;
}
